//go:build vectors

package search

import (
	"fmt"
	"sort"
	"strings"

	"github.com/<HOME>/bleve/v2"
	bleveSearch "github.com/<HOME>/bleve/v2/search"
)

// Read retrieves a section by qualified ID or a document TOC by slug.
func (s *Searcher) Read(id string, contextN int) (ReadResponse, error) {
	if contextN < 0 {
		contextN = 0
	}
	if contextN > 5 {
		contextN = 5
	}

	if strings.Contains(id, ":") {
		return s.readSection(id, contextN)
	}
	return s.readDocumentTOC(id)
}

// readSection retrieves a single section by qualified ID.
func (s *Searcher) readSection(qualifiedID string, contextN int) (ReadResponse, error) {
	query := bleve.NewTermQuery(qualifiedID)
	query.SetField("qualifiedId")
	req := bleve.NewSearchRequest(query)
	req.Size = 1
	req.Fields = []string{
		"qualifiedId", "documentSlug", "sectionId", "title",
		"content", "scope", "kind", "tags", "position",
	}

	results, err := s.index.Search(req)
	if err != nil {
		return ReadResponse{}, fmt.Errorf("search by qualifiedId: %w", err)
	}

	if len(results.Hits) == 0 {
		return ReadResponse{
			Mode:  "section",
			Found: false,
			Error: &ReadError{
				Code:    "not_found",
				Message: fmt.Sprintf("section %q does not exist in the index", qualifiedID),
			},
		}, nil
	}

	hit := results.Hits[0]
	section := docMatchToReadSection(hit)

	resp := ReadResponse{
		Mode:    "section",
		Found:   true,
		Section: &section,
	}

	if contextN > 0 {
		contextSections, err := s.getContextSections(section.DocumentSlug, section.Position, contextN)
		if err == nil {
			resp.Context = contextSections
		}
	}

	return resp, nil
}

// readDocumentTOC retrieves all sections for a document slug.
func (s *Searcher) readDocumentTOC(slug string) (ReadResponse, error) {
	query := bleve.NewTermQuery(slug)
	query.SetField("documentSlug")
	req := bleve.NewSearchRequest(query)
	req.Size = 10000
	req.Fields = []string{
		"qualifiedId", "documentSlug", "sectionId", "title",
		"scope", "kind", "tags", "position",
	}
	req.SortBy([]string{"position"})

	results, err := s.index.Search(req)
	if err != nil {
		return ReadResponse{}, fmt.Errorf("document lookup: %w", err)
	}

	if len(results.Hits) == 0 {
		return s.checkAmbiguous(slug)
	}

	firstHit := results.Hits[0]
	docMeta := &ReadDocMeta{
		Slug:         slug,
		Title:        getString(firstHit.Fields, "title"),
		Scope:        getString(firstHit.Fields, "scope"),
		Kind:         getString(firstHit.Fields, "kind"),
		Tags:         getStringSlice(firstHit.Fields, "tags"),
		SectionCount: len(results.Hits),
	}

	sections := make([]SectionEntry, 0, len(results.Hits))
	for _, hit := range results.Hits {
		sections = append(sections, SectionEntry{
			SectionID:   getString(hit.Fields, "sectionId"),
			Title:       getString(hit.Fields, "title"),
			QualifiedID: getString(hit.Fields, "qualifiedId"),
		})
	}

	sort.Slice(sections, func(i, j int) bool {
		return getInt(results.Hits[i].Fields, "position") < getInt(results.Hits[j].Fields, "position")
	})

	return ReadResponse{
		Mode:     "toc",
		Found:    true,
		Document: docMeta,
		Sections: sections,
	}, nil
}

func (s *Searcher) checkAmbiguous(sectionID string) (ReadResponse, error) {
	query := bleve.NewTermQuery(sectionID)
	query.SetField("sectionId")
	req := bleve.NewSearchRequest(query)
	req.Size = 100
	req.Fields = []string{"qualifiedId", "documentSlug"}

	results, err := s.index.Search(req)
	if err != nil {
		return ReadResponse{}, err
	}

	if len(results.Hits) == 0 {
		return ReadResponse{
			Mode:  "toc",
			Found: false,
			Error: &ReadError{
				Code:    "not_found",
				Message: fmt.Sprintf("document %q does not exist in the index", sectionID),
			},
		}, nil
	}

	if len(results.Hits) == 1 {
		hit := results.Hits[0]
		qualifiedID := getString(hit.Fields, "qualifiedId")
		return s.readSection(qualifiedID, 0)
	}

	options := make([]string, 0, len(results.Hits))
	seen := make(map[string]bool)
	for _, hit := range results.Hits {
		qid := getString(hit.Fields, "qualifiedId")
		if !seen[qid] {
			options = append(options, qid)
			seen[qid] = true
		}
	}

	return ReadResponse{
		Mode:  "section",
		Found: false,
		Error: &ReadError{
			Code:    "ambiguous_id",
			Message: fmt.Sprintf("%q exists in multiple documents: %s. Use the qualified ID.", sectionID, strings.Join(options, ", ")),
			Options: options,
		},
	}, nil
}

func (s *Searcher) getContextSections(slug string, position, contextN int) ([]ReadSection, error) {
	query := bleve.NewTermQuery(slug)
	query.SetField("documentSlug")
	req := bleve.NewSearchRequest(query)
	req.Size = 10000
	req.Fields = []string{
		"qualifiedId", "documentSlug", "sectionId", "title",
		"content", "scope", "kind", "tags", "position",
	}

	results, err := s.index.Search(req)
	if err != nil {
		return nil, err
	}

	type sectionByPos struct {
		section  ReadSection
		position int
	}

	var allSections []sectionByPos
	for _, hit := range results.Hits {
		pos := getInt(hit.Fields, "position")
		allSections = append(allSections, sectionByPos{
			section:  docMatchToReadSection(hit),
			position: pos,
		})
	}

	sort.Slice(allSections, func(i, j int) bool {
		return allSections[i].position < allSections[j].position
	})

	var context []ReadSection
	minPos := position - contextN
	maxPos := position + contextN

	for _, s := range allSections {
		if s.position >= minPos && s.position <= maxPos && s.position != position {
			context = append(context, s.section)
		}
	}

	return context, nil
}

func docMatchToReadSection(hit *bleveSearch.DocumentMatch) ReadSection {
	return ReadSection{
		QualifiedID:  getString(hit.Fields, "qualifiedId"),
		DocumentSlug: getString(hit.Fields, "documentSlug"),
		SectionID:    getString(hit.Fields, "sectionId"),
		Title:        getString(hit.Fields, "title"),
		Content:      getString(hit.Fields, "content"),
		Scope:        getString(hit.Fields, "scope"),
		Kind:         getString(hit.Fields, "kind"),
		Tags:         getStringSlice(hit.Fields, "tags"),
		Position:     getInt(hit.Fields, "position"),
	}
}
